public static long solve(long m, long n, long[][] waitCost) {
    int M = (int) m;
    int N = (int) n;
    long INF = Long.MAX_VALUE / 2;
    long[][] dp0 = new long[M][N];
    long[][] dp1 = new long[M][N];

    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N; j++) {
            dp0[i][j] = INF;
            dp1[i][j] = INF;
        }
    }
    dp1[0][0] = 1;

    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N; j++) {
            if (dp0[i][j] != INF) {
                long candidate = dp0[i][j] + waitCost[i][j];
                if (candidate < dp1[i][j]) {
                    dp1[i][j] = candidate;
                }
            }

            if (dp1[i][j] != INF) {
                if (i + 1 < M) {
                    long cost = dp1[i][j] + (long)(i + 2) * (j + 1);
                    if (cost < dp0[i + 1][j]) {
                        dp0[i + 1][j] = cost;
                    }
                }
                if (j + 1 < N) {
                    long cost = dp1[i][j] + (long)(i + 1) * (j + 2);
                    if (cost < dp0[i][j + 1]) {
                        dp0[i][j + 1] = cost;
                    }
                }
            }
        }
    }

    return Math.min(dp0[M-1][N-1], dp1[M-1][N-1]);
}
```

