        dp0[1][0] = 1 + (2) * (1);
    }

    for (int i = 0; i < M; i++) {
        for (int j = 0; j < N; j++) {
            if (i > 0) {
                long cost = dp1[i-1][j] + (i+1) * (j+1);
                if (cost < dp0[i][j]) {
                    dp0[i][j] = cost;
                }
